import{_ as a,o as i,c,ai as l}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"RPC 适配器","description":"","frontmatter":{"read_when":["添加或更改外部 CLI 集成","调试 RPC 适配器（signal-cli、imsg）"],"summary":"外部 CLI（signal-cli、imsg）的 RPC 适配器和 Gateway 网关模式","title":"RPC 适配器","x-i18n":{"generated_at":"2026-02-03T07:53:44Z","model":"claude-opus-4-5","provider":"pi","source_hash":"c04edc952390304a22a3a4763aca00a0311b38d390477ec0be5fe485ec257fa7","source_path":"reference/rpc.md","workflow":15}},"headers":[],"relativePath":"zh-CN/reference/rpc.md","filePath":"zh-CN/reference/rpc.md","lastUpdated":null}'),s={name:"zh-CN/reference/rpc.md"};function d(o,e,t,r,n,h){return i(),c("div",null,[...e[0]||(e[0]=[l('<h1 id="rpc-适配器" tabindex="-1"><a class="header-anchor" href="#rpc-适配器">#</a> RPC 适配器</h1><p>OpenSoul 通过 JSON-RPC 集成外部 CLI。目前使用两种模式。</p><h2 id="模式-a-http-守护进程-signal-cli" tabindex="-1"><a class="header-anchor" href="#模式-a-http-守护进程-signal-cli">#</a> 模式 A：HTTP 守护进程（signal-cli）</h2><ul><li><code>signal-cli</code> 作为守护进程运行，通过 HTTP 使用 JSON-RPC。</li><li>事件流是 SSE（<code>/api/v1/events</code>）。</li><li>健康探测：<code>/api/v1/check</code>。</li><li>当 <code>channels.signal.autoStart=true</code> 时，OpenSoul 负责生命周期管理。</li></ul><p>设置和端点参见 <a href="/docs/channels/signal">Signal</a>。</p><h2 id="模式-b-stdio-子进程-imsg" tabindex="-1"><a class="header-anchor" href="#模式-b-stdio-子进程-imsg">#</a> 模式 B：stdio 子进程（imsg）</h2><ul><li>OpenSoul 将 <code>imsg rpc</code> 作为子进程生成。</li><li>JSON-RPC 是通过 stdin/stdout 的行分隔格式（每行一个 JSON 对象）。</li><li>无需 TCP 端口，无需守护进程。</li></ul><p>使用的核心方法：</p><ul><li><code>watch.subscribe</code> → 通知（<code>method: &quot;message&quot;</code>）</li><li><code>watch.unsubscribe</code></li><li><code>send</code></li><li><code>chats.list</code>（探测/诊断）</li></ul><p>设置和寻址（首选 <code>chat_id</code>）参见 <a href="/docs/channels/imessage">iMessage</a>。</p><h2 id="适配器指南" tabindex="-1"><a class="header-anchor" href="#适配器指南">#</a> 适配器指南</h2><ul><li>Gateway 网关负责进程（启动/停止与提供商生命周期绑定）。</li><li>保持 RPC 客户端弹性：超时、退出时重启。</li><li>优先使用稳定 ID（例如 <code>chat_id</code>）而非显示字符串。</li></ul>',12)])])}const _=a(s,[["render",d]]);export{u as __pageData,_ as default};
